        {id: 3, term: "\u970d\u9aa0(pi\u00e0o)\u59da", definition: "\u5373\u897f\u6c49\u540d\u5c06\u970d\u53bb\u75c5\u3002", definitionEn: "Huo Qubing, famous Western Han general."}
